import React, { useState } from 'react';
import toast from 'react-hot-toast';
import CampaignOverview from '../components/CampaignOverview';
import VideoTable from '../components/VideoTable';
import DailyViewsChart from '../components/DailyViewsChart';
import TopCreatorsChart from '../components/TopCreatorsChart';
import { triggerScrape } from '../services/api';

export default function Dashboard() {
  const [scraping, setScraping] = useState(false);

  const handleScrapeNow = async () => {
    setScraping(true);
    try {
      const res = await triggerScrape();
      toast.success(`Scraped ${res.data.scraped} videos`);
      setTimeout(() => window.location.reload(), 1500);
    } catch (err) {
      toast.error(err.response?.data?.error || 'Scrape failed');
    } finally {
      setScraping(false);
    }
  };

  return (
    <div>
      <div className="page-header">
        <h1>Dashboard</h1>
        <button
          className="btn btn-primary"
          disabled={scraping}
          onClick={handleScrapeNow}
        >
          {scraping ? 'Scraping…' : 'Scrape Now'}
        </button>
      </div>

      <CampaignOverview />

      <div className="charts-row">
        <DailyViewsChart />
        <TopCreatorsChart />
      </div>

      <VideoTable />
    </div>
  );
}
